fn solve(nums: Vec<i64>) -> i64 {
    let n = nums.len();
    let mut ones_indices = Vec::new();
    let mut twos_indices = Vec::new();

    // Collect indices of 1s and 2s
    for (i, &val) in nums.iter().enumerate() {
        let index = i as i64;
        if val == 1 {
            ones_indices.push(index);
        } else if val == 2 {
            twos_indices.push(index);
        }
    }

    // If either 1s or 2s are missing, no valid pairs exist
    if ones_indices.is_empty() || twos_indices.is_empty() {
        return -1;
    }

    let mut min_diff = i64::MAX;

    // Iterate over all pairs (i, j) where nums[i] == 1 and nums[j] == 2
    for &i in ones_indices.iter() {
        for &j in twos_indices.iter() {
            let diff = (i - j).abs();
            if diff < min_diff {
                min_diff = diff;
            }
        }
    }

    if min_diff == i64::MAX {
        // This case should technically not be reached if both lists are non-empty,
        // but it's a safety check.
        -1
    } else {
        min_diff
    }
}
